from uuid import uuid4import httpxfrom a2a.client import A2ACardResolver, A2AClientfrom a2a.types import MessageSendParams, SendMessageRequestfrom openai import OpenAIclient = OpenAI(api_key="...")def select_best_agent(prompt,                       agents_cards):    card_selection_prompt = f"""    Given the following user prompt: "{prompt}", choose the best matching agent card from the list below:        {agents_cards}    Just return the index of the best matching agent. Return -1 if no agent is suitable.    """    response = client.responses.create(model="gpt-4.1",                                       input=card_selection_prompt)    try:        agent_id = int(response.output_text)        if 0 <= agent_id <= len(agents_cards) - 1:            pass        elif agent_id == -1:            raise Exception("No agent is capable to respond to the prompt.")        else:            raise Exception("Unexpected agent ID.")    except:        raise Exception("Unexpected response from the LLM")    return agent_idasync def main():        agents_base_urls = ['http://localhost:9999',                        'http://localhost:8888'                        ]        httpx_client = httpx.AsyncClient(timeout=10)    selected_agent_card = None    all_agents_cards = []    for agent_base_url in agents_base_urls:        resolver = A2ACardResolver(httpx_client=httpx_client,                                   base_url=agent_base_url)        try:            agent_card = (await resolver.get_agent_card())            all_agents_cards.append(agent_card)        except Exception as e:            raise RuntimeError('Failed to fetch the public agent card. Cannot continue.') from e    if len(all_agents_cards) == 0:        raise RuntimeError('Failed to find any agent card.')    prompt = 'Suggest a good pasta recipe'    selected_agent_index = select_best_agent(prompt=prompt,                                             agents_cards=all_agents_cards)    selected_agent_card = all_agents_cards[selected_agent_index]    client = A2AClient(httpx_client=httpx_client,                        agent_card=selected_agent_card)    send_message_payload = {        'message': {            'role': 'user',            'parts': [{'kind': 'text', 'text': prompt}],            'messageId': uuid4().hex,        },    }    request = SendMessageRequest(id=str(uuid4()),                                      params=MessageSendParams(**send_message_payload))    response = await client.send_message(request)    print(f"Generated Response: {response}")if __name__ == '__main__':    import asyncio    asyncio.run(main())